package com.ynxweb4.browser;

import android.app.*;import android.content.*;import android.graphics.Color;import android.net.*;import android.net.http.SslError;import android.os.*;import android.view.*;import android.webkit.*;import android.widget.*;

public final class PrivateActivity extends Activity {
  private WebView web;private EditText address;private TextView status;
  @Override protected void attachBaseContext(Context base){if(Build.VERSION.SDK_INT>=28)WebView.setDataDirectorySuffix("private");super.attachBaseContext(base);}
  @Override public void onCreate(Bundle state){super.onCreate(state);buildUi();web.loadUrl(AppConfig.SEARCH_URL);}
  private Button button(String text,View.OnClickListener click){Button value=new Button(this);value.setText(text);value.setAllCaps(false);value.setTextColor(Color.rgb(0,60,255));value.setOnClickListener(click);value.setContentDescription(text);return value;}
  private void buildUi(){LinearLayout root=new LinearLayout(this);root.setOrientation(LinearLayout.VERTICAL);root.setBackgroundColor(Color.rgb(20,20,24));status=new TextView(this);status.setTextColor(Color.WHITE);status.setPadding(24,18,24,18);status.setText("PRIVATE · no YNX history, recovery, permission persistence or AI\nSites, networks, Android and downloaded files may retain activity.");status.setAccessibilityLiveRegion(View.ACCESSIBILITY_LIVE_REGION_POLITE);root.addView(status);LinearLayout nav=new LinearLayout(this);nav.setGravity(Gravity.CENTER_VERTICAL);nav.addView(button("←",v->{if(web.canGoBack())web.goBack();}));nav.addView(button("↻",v->web.reload()));address=new EditText(this);address.setSingleLine(true);address.setTextColor(Color.WHITE);address.setHintTextColor(Color.LTGRAY);address.setHint("Private search or address");address.setOnEditorActionListener((v,a,e)->{web.loadUrl(normalize(address.getText().toString()));return true;});nav.addView(address,new LinearLayout.LayoutParams(0,-2,1));nav.addView(button("Done",v->finishAndRemoveTask()));root.addView(nav);web=new WebView(this);WebSettings settings=web.getSettings();settings.setJavaScriptEnabled(true);settings.setDomStorageEnabled(false);settings.setDatabaseEnabled(false);settings.setAllowFileAccess(false);settings.setAllowContentAccess(true);settings.setMixedContentMode(WebSettings.MIXED_CONTENT_NEVER_ALLOW);settings.setSafeBrowsingEnabled(true);settings.setCacheMode(WebSettings.LOAD_NO_CACHE);CookieManager.getInstance().setAcceptCookie(true);CookieManager.getInstance().setAcceptThirdPartyCookies(web,false);web.setWebViewClient(new WebViewClient(){@Override public void onPageStarted(WebView view,String url,android.graphics.Bitmap icon){status.setText("PRIVATE · loading without persistent YNX state");}@Override public void onPageFinished(WebView view,String url){address.setText(url);status.setText(url.startsWith("https://")?"PRIVATE · HTTPS system trust · no YNX history or recovery":"PRIVATE · not HTTPS · transport is not encrypted");}@Override public void onReceivedSslError(WebView view,SslErrorHandler handler,SslError error){handler.cancel();status.setText("PRIVATE · certificate error · navigation stopped");}@Override public boolean shouldOverrideUrlLoading(WebView view,WebResourceRequest request){Uri url=request.getUrl();if("ynxwallet".equals(url.getScheme())||"ynx-wallet".equals(url.getScheme())){new AlertDialog.Builder(PrivateActivity.this).setTitle("Wallet review").setMessage("Review requester, callback, scopes, account, network, expiry and every transaction field in YNX Wallet. This browser never signs. Private mode does not hide Wallet activity from the Wallet, OS or network.").setPositiveButton("Close",null).show();return true;}return false;}});web.setWebChromeClient(new WebChromeClient(){@Override public void onPermissionRequest(PermissionRequest request){runOnUiThread(()->new AlertDialog.Builder(PrivateActivity.this).setTitle("Private site permission").setMessage(request.getOrigin()+"\n\nThis decision is not saved.").setNegativeButton("Deny",(d,w)->request.deny()).setPositiveButton("Allow once",(d,w)->request.grant(request.getResources())).setOnCancelListener(d->request.deny()).show());}});web.setDownloadListener((url,userAgent,contentDisposition,mime,length)->new AlertDialog.Builder(this).setTitle("Private download boundary").setMessage("Downloaded files remain visible to Android and other apps. YNX Browser cannot erase that external trace automatically.").setNegativeButton("Cancel",null).setPositiveButton("Continue",(d,w)->{DownloadManager.Request request=new DownloadManager.Request(Uri.parse(url));request.setNotificationVisibility(DownloadManager.Request.VISIBILITY_VISIBLE_NOTIFY_COMPLETED);request.setDestinationInExternalPublicDir(android.os.Environment.DIRECTORY_DOWNLOADS,URLUtil.guessFileName(url,contentDisposition,mime));((DownloadManager)getSystemService(DOWNLOAD_SERVICE)).enqueue(request);}).show());root.addView(web,new LinearLayout.LayoutParams(-1,0,1));setContentView(root);}
  private String normalize(String input){String value=input.trim();if(value.matches("https?://.*"))return value;if(value.contains(" ")||!value.contains("."))return AppConfig.SEARCH_URL+"/?q="+Uri.encode(value);return"https://"+value;}
  @Override protected void onDestroy(){if(web!=null){web.stopLoading();web.clearHistory();web.clearCache(true);web.clearFormData();web.destroy();}CookieManager.getInstance().removeAllCookies(null);CookieManager.getInstance().flush();WebStorage.getInstance().deleteAllData();super.onDestroy();}
}
